	public function EvtAfterWriteRackPowerMgmt(Combodo\iTop\Service\Events\EventData $oEventData)
	{

		// Creation flag
		// $oEventData->Get('is_new') returns a boolean

		// For updates, the list of changes done during this operation
		// $oEventData->Get('changes') returns an array
		//We calculate location's contracted_power
		if($oEventData->Get('is_new')) {
		    //create mode defualt value contracted_power=0
		    $this->ComputeLocationContractedPower();
		    //Customer Contract Mgmt
    		$this->ComputeCustomerContractContractedPower();
		} else {
		    //update => $achanges = old value to change, $this = new value
    		$aChanges = $this->ListPreviousValuesForUpdatedAttributes();
    		if (array_key_exists('contracted_power', $aChanges) || array_key_exists('power_reading_value', $aChanges)) {
				IssueLog::Debug("Rack: Calculate Power Values", 'Delta XML');
				$this->ComputeLocationContractedPower();
				$this->ComputeCustomerContractContractedPower();
		    }
		}

	}

	public function ComputeCustomerContractContractedPower()
	{
		// Put your code here, call parent::ComputeContractedPower(...); if needed
        if(empty($this->Get('customer_id'))){
            return true;
        }

		$sOQL = "SELECT CustomerContract WHERE org_id= :customer_id";
		$oSearch=DBObjectSearch::FromOQL($sOQL);
		$oSearch->AllowAllData();
		$oConnectionSet = new DBObjectSet($oSearch,
			array(),
			array(
				'customer_id' => $this->Get('customer_id')
			)
		);
		while($oCustomerContract = $oConnectionSet->Fetch()){
		    IssueLog::Debug("Rack: Calculate Power Values CC for ".$oCustomerContract->Get("name"), 'Delta XML');
		    //installed_power
		    $oCustomerContract->ComputeCustomerContractInstalledPower();

		    //power_reading_value
		    $oCustomerContract->ComputeCustomerContractPowerReadingValue();

		}
		return true;
	}

	public function ComputeLocationContractedPower()
	{
		// Put your code here, call parent::ComputeLocationContractedPower(...); if needed
		if(empty($this->Get('location_id'))){
            return true;
        }

		$sOQL = "SELECT Location AS root JOIN Location AS child ON child.parent_id BELOW root.id WHERE child.id= :location_id";
		$oSearch=DBObjectSearch::FromOQL($sOQL);
		$oSearch->AllowAllData();
		$oConnectionSet = new DBObjectSet($oSearch,
			array(),
			array(
				'location_id' => $this->Get('location_id')
			)
		);
		while($oLocation = $oConnectionSet->Fetch()){
		    IssueLog::Debug("Rack: Calculate Power Values Loc for ".$oLocation->Get("name"), 'Delta XML');
		    //contracted_power
		    $oLocation->ComputeLocationContractedPower();

		    //power_reading_value
		    $oLocation->ComputeLocationPowerReadingValue();

		}
		return true;
	}

public function onDelete()
{
	// Put your code here, call parent::onDelete(...); if needed
	//remove contracted_power
    $this->ComputeLocationContractedPower();
    //Customer Contract Mgmt
	$this->ComputeCustomerContractContractedPower();

	parent::onDelete();
}

public function EvtComputeValuesRackPowerData(Combodo\iTop\Service\Events\EventData $oEventData)
{
    if($this->Get('status')=='obsolete') {
        $this->Set('contracted_power', 0);
        $this->Set('installed_power', 0);
        $this->Set('power_reading_value', 0);
    }
}

	public function CalculatePowerReadingUsage()
	{
		IssueLog::Debug("Location Percent usage of Contracted Power: Name: ".$this->Get('name'), 'Delta XML');
		// Put your code here, call parent::CalculatePowerReadingUsage(...); if needed
		$fPowerReading = (float) $this->Get('power_reading_value');

        $fContractedPower = (float) $this->Get('contracted_power');
        //IssueLog::Debug("Location Percent usage of Contracted Power: Name: ".$this->Get('name'). " Contracted Power: " .$fContractedPower." Reading Value Value: ".$fPowerReading, 'Delta XML');
        if($fContractedPower > 0)
        {
                // Round with precision of 2 to keep an integer
                $fPowerUsage = round($fPowerReading / $fContractedPower, 2) * 100;
                //IssueLog::Debug("Location Name: ".$this->Get('name')." Reading Contracted Usage Value: ".$fPowerUsage, 'Delta XML');
                $this->Set('power_contracted_usage', $fPowerUsage);
        } else {
            $this->Set('power_contracted_usage', 0);
        }

        $fInstalledPower = (float) $this->Get('installed_power');
        //IssueLog::Debug("Location Percent usage of Installed Power: Name: ".$this->Get('name'). " Installed Power: " .$fInstalledPower." Reading Value Value: ".$fPowerReading, 'Delta XML');
        if($fInstalledPower > 0)
        {
                // Round with precision of 2 to keep an integer
                $fPowerUsage = round($fPowerReading / $fInstalledPower, 2) * 100;
                //IssueLog::Debug("Location Name: ".$this->Get('name')." Reading Installed Usage Value: ".$fPowerUsage, 'Delta XML');
                $this->Set('power_installed_usage', $fPowerUsage);
        } else {
            $this->Set('power_installed_usage', 0);
        }
	}

public function EvtComputeValuesRackPower(Combodo\iTop\Service\Events\EventData $oEventData)
{
    $this->CalculatePowerReadingUsage();
}

