public function ComputeCustomerContractInstalledPower()
{
	// Put your code here, call parent::ComputeCustomerContractInstalledPower(...); if needed
	$icontracted_power=$this->CalculatePowerData('contracted_power');

	IssueLog::Debug("Customer contract Name: ".$this->Get('name')." New Installed Value: ".$icontracted_power, 'Delta XML');
	$this->Set('installed_power',$icontracted_power);
	$this->CalculatePowerReadingUsage();
	$this->DBUpdate();
}

public function ComputeCustomerContractPowerReadingValue()
{
