	$oSearch=DBObjectSearch::FromOQL($sOQL);
	$oSearch->AllowAllData();
	$oConnectionSet = new DBObjectSet($oSearch,
		array(),
		array(
			'customer_id' => $this->Get('org_id')
		)
	);
	$iTotalPower=0;
	//On ajoute tous
	while($oRack = $oConnectionSet->Fetch()){
	    //If contracted_power is empty, we set at 0
	    $iRackPowerValue=$oRack->Get($sPowerValue);
	    if ($iRackPowerValue=='' || $iRackPowerValue<0) {
	        $iRackPowerValue=0;
	    }
	    $iTotalPower+=$iRackPowerValue;
	}
	//IssueLog::Debug("Calculated Power: " .$sPowerValue." Total Power: ".$iTotalPower, 'Delta XML');
	return $iTotalPower;
}

