public function CalculatePowerData($sPowerReading)
{
	// Put your code here, call parent::CalculatePowerData(...); if needed
	IssueLog::Debug("Location Power data from Rack: Name: ".$this->Get('name'), 'Delta XML');
	$sOQL = "SELECT Rack AS R JOIN Location AS root ON R.location_id=root.id JOIN Location AS child ON child.parent_id ABOVE root.id WHERE child.id= :location_id AND R.status='production'";
	$oSearch=DBObjectSearch::FromOQL($sOQL);
	$oSearch->AllowAllData();
	$oConnectionSet = new DBObjectSet($oSearch,
		array(),
		array(
			'location_id' => $this->GetKey()
		)
	);
	$icontracted_power=0;
	//On ajoute tous
	while($oRack = $oConnectionSet->Fetch()){
	    //If contracted_power is empty, we set at 0
	    $iRackPowerValue=$oRack->Get($sPowerReading);
	    if ($iRackPowerValue=='' || $iRackPowerValue<0) {
	        $iRackPowerValue=0;
	    }
	    $icontracted_power+=$iRackPowerValue;
	}
	return $icontracted_power;
}

